import React, { useEffect, useState, useMemo, useCallback } from "react";
import api from "./api";
import Navbar from "./Navbar";

export default function SalaryDashboard() {
  const [salaries, setSalaries] = useState([]);
  const [form, setForm] = useState({ amount: "", month: "", year: "", employee_id: "" });
  const [editId, setEditId] = useState(null);
  const [message, setMessage] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const fetchSalaries = useCallback(async () => {
    setLoading(true);
    try {
      const res = await api.get("/salaries/");
      setSalaries(res.data);
    } catch (err) {
      setError("Failed to fetch salaries");
    }
    setLoading(false);
  }, []);

  useEffect(() => { fetchSalaries(); }, [fetchSalaries]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    try {
      const payload = {
        amount: parseFloat(form.amount),
        month: form.month,
        year: parseInt(form.year),
        employee_id: parseInt(form.employee_id)
      };
      if (editId) {
        await api.put(`/salaries/${editId}`, payload);
        setMessage("Record updated");
      } else {
        await api.post("/salaries/", payload);
        setMessage("Record created");
      }
      setForm({ amount: "", month: "", year: "", employee_id: "" });
      setEditId(null);
      fetchSalaries();
    } catch (err) {
      setError("Operation failed");
    }
    setLoading(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Delete this record?")) return;
    try {
      await api.delete(`/salaries/${id}`);
      fetchSalaries();
    } catch (err) {
      setError("Delete failed");
    }
  };

  return (
    <div className="app-bg">
      <Navbar />
      <div className="container">
        <div className="content-grid">
          <div className="card form-card">
            <h2>{editId ? "Edit Salary" : "Add Salary"}</h2>
            <form onSubmit={handleSubmit} className="product-form">
              <input type="number" placeholder="Amount" value={form.amount} onChange={e => setForm({...form, amount: e.target.value})} required />
              <input type="text" placeholder="Month" value={form.month} onChange={e => setForm({...form, month: e.target.value})} required />
              <input type="number" placeholder="Year" value={form.year} onChange={e => setForm({...form, year: e.target.value})} required />
              <input type="number" placeholder="User ID" value={form.employee_id} onChange={e => setForm({...form, employee_id: e.target.value})} required />
              <button className="btn" type="submit">{editId ? "Update" : "Add"}</button>
            </form>
            {message && <div className="success-msg">{message}</div>}
            {error && <div className="error-msg">{error}</div>}
          </div>

          <div className="card list-card">
            <h2>Salary Records</h2>
            <div className="scroll-x">
              <table className="product-table">
                <thead>
                  <tr>
                    <th>User ID</th>
                    <th>Amount</th>
                    <th>Month/Year</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {salaries.map((s) => (
                    <tr key={s.id}>
                      <td>{s.employee_id}</td>
                      <td className="price-cell">${s.amount}</td>
                      <td>{s.month} {s.year}</td>
                      <td>
                        <div className="row-actions">
                          <button className="btn btn-edit" onClick={() => {setEditId(s.id); setForm(s);}}>Edit</button>
                          <button className="btn btn-delete" onClick={() => handleDelete(s.id)}>Delete</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
